-- Importacao de leads convertidos a partir do arquivo RELARATORIO COMERCIAL PARA TRANFERIR.xlsx
-- Todos os registros abaixo entram como segmento LEAD e status CONVERTIDO.
-- A cidade do relatorio foi convertida para o grupo do cliente conforme mapa informado.
BEGIN;

INSERT INTO eventos (evento, segmento)
SELECT seed.evento, 'LEAD'
FROM (VALUES
    ('ATIVA'),
    ('LOJA FISICA'),
    ('WHATSAPP')
) AS seed(evento)
WHERE NOT EXISTS (
    SELECT 1 FROM eventos e WHERE e.evento = seed.evento AND e.segmento = 'LEAD'
);

INSERT INTO atividades (
    evento, cliente, data, usuario, segmento, valor, status,
    codigo_cliente, grupo_cliente, plano, valor_plano, convertido_em, convertido_por
)
